<template>
    <section>
        <tg-list ref="tgList" :listType="['List']" :IsShowAction="IsShowAction" :showCheckBox="false"
            ModuleName="PROJECT" SubModuleCode="Task" IdentityColumn="task_id" :HeaderText="$t('ProjectTasks')"
            :ListData="ListingData" :HeaderData="Headers" :widgets="widgets" :HeaderButtons="Buttons"
            :TotalRecords="TotalRecords" :RenderRowActionMethod="renderActions" :LegendArray="LegendArray"
            :SearchFields="false" :ListDataCallBackFunction="FetchTaskList" :SortExp="SortExp" :SortBy="SortBy"
            :NorecordfoundText="$t('NoRecordfound')" v-on:PagerButtonClick="pagerMethod" tableClasses="overflow-visible"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'status_name'">
                    <listing-status :isfor="'TASKLISTING'" ref="updatestatus" v-bind:dataid="data.row.task_id"
                        data-controller="Task" v-bind:statuslist="StatusList" v-bind:item="data"
                        v-bind:parentid="data.row.task_id" data-action="index"
                        v-bind:dataselected="data.row.status_name" v-bind:callbackfunction="FetchTaskList"
                        v-bind:isselectedvaluestring="true">
                    </listing-status>
                </template>
                
                <template v-if="data.column.COLUMN_NAME == 'priority_name'">
                    <span v-if="data.row.priority_name != null">
                        <span v-bind:style="{ backgroundColor: data.row.color_code }"
                            class="text-center text-white d-block">
                            {{ data.row.priority_name }}
                        </span>
                    </span>
                    <span class="text-center d-block" v-else>N/A</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'task_name'">              
                    <a class="task-dec" @click="ParentTask(data.row)" :title="data.row.task_name" style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;">
                        <span v-if="data.row.task_type === 'T'" class="text-primary fa fa-check-square mr-1"
                                title="Task"></span>
                            <span v-else-if="data.row.task_type === 'B'" class="text-danger fa fa-warning mr-1"
                                title="Bug"></span>
                            <span v-else-if="data.row.task_type === 'S'" class="text-success fa fa-film mr-1"
                                title="Story"></span>
                            {{ data.row.task_number }} {{ data.row.task_name }}
                    </a>                                   
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_start_date'">
                    <div :title="data.row.planned_start_date == null ? '--' : $d(data.row.planned_start_date)">
                        {{
                            data.row.planned_start_date == null ? '--' : $d(data.row.planned_start_date)
                        }}
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_end_date'">
                    <div :title="data.row.planned_end_date == null ? '--' : $d(data.row.planned_end_date)">
                        {{ data.row.planned_end_date == null ? '--' : $d(data.row.planned_end_date) }}
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'task_description'">
            <span   :title="stripHtmlTags(data.row.task_description)" style="white-space: nowrap;  word-wrap: break-word;  overflow: hidden;    text-overflow: ellipsis;" v-html="TruncateStr(data.row.task_description,30)">
            </span>
        </template>
                <template v-if="data.column.COLUMN_NAME == 'CompleteTask'">
                    <div class="Task" :title="data.row.Current_Progress +'%'">
                        <div :class="['c100', 'small', 'green', 'p' + parseInt(data.row.Current_Progress)]">
                            <span>{{ data.row.Current_Progress }}%</span>
                            <div class="slice">
                                <div class="bar"></div>
                                <div class="fill"></div>
                            </div>                              
                        </div>
                    </div>
                    <a href="javascript:;" @click="CheckDisabled() && UpdateProgress(data.row)"  v-if="data.row.status_name !='Completed'"
                        :title="data.row.Current_Progress"
                        :class="{ 'text-success': true, 'align-top': true, 'mt-3': true, 'd-inline-block': true, 'text-right': true, 'single-action': true, 'disabled': !CheckDisabled() }"
                        data-toggle-tooltip="tooltip" data-original-title="Manage Progress"><em
                            class="fa fa-pencil action-icon"></em></a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'Team'">
                    <div   class="user-count-wrapper" @mouseover="showAssignUser(data.row) && CheckDisabled()"
                        @mouseleave="hideAssignUser(data.row) && CheckDisabled()">
                        <span v-if="data.row.Number == 0">
                            <a @click="OpenAssignedUser(data.row)"
                                :class="['text-dark', 'single-action', { 'disabled': !CheckDisabled() }]"
                                :href="CheckDisabled() ? 'javascript:;' : '#'">
                                <em class="fa fa-user-plus"></em>
                            </a>
                        </span>
                        <span v-else>
                            <a @click="OpenAssignedUser(data.row)"
                                :class="['text-dark', 'single-action', { 'disabled': !CheckDisabled() }]"
                                :href="CheckDisabled() ? 'javascript:;' : '#'">
                                <em class="fa fa-user"></em>
                                <span class="noti-circle noti-green">{{ data.row.Number }}</span>
                            </a>
                        </span>
                        <div class="viewmoretagsbase_ptl showTags" v-if="data.row.ispopover">
                            <div class="popover-arrowss_ptl"></div>
                            <div class="viewmoretags_ptl">
                                <span class="head" title="Prashant shukla QA">{{ $t(TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team') }}</span>
                                <div class="outerbase">
                                    <span v-for="(item, index) in data.row.AssignUser" :key="index" title="test">{{
                                        index
                                        +1}}. {{ TruncateStr(item, 15) }}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </template>
            </template>
        </tg-list>
        <projectTaskAddpopup v-if="ProjectTaskListingpopup"></projectTaskAddpopup>
        <div class="add-backlog-btn border bg-light float-left w-100 p-3" v-if="CheckDisabled()">
            <a v-if="!IsAddTask" class="w-100 text-dark" @click="AddTask" type="button"><em
                    class="fa fa-plus pr-2"></em>{{
                        $t('Create') }} {{ $t(NewTabName) }}</a>
            <div class="input-group w-100 " v-if="IsAddTask">
                <div class="input-group-prepend border-right-0">
                    <span class="input-group-text bg-white px-2" id="basic-addon1"><em
                            class="fa fa-check-square epic-timeline"></em></span>
                </div>
                <input type="text" @keydown.enter="SaveTask" v-model="txtTaskTitle"
                    class="form-control px-1 bg-white border-left-0" :placeholder="`${$t('Enter')} ${$t(NewTabName)} ${$t('Name')}`"
                    aria-label="" aria-describedby="basic-addon1">
                <div class="col-sm-1 pt-1">
                    <a class="actions-onclick" title="Save" @click="SaveTask"><em
                            class="fa fa-save action-icon text-success"></em></a>
                    <a @click="IsHideAddTask" title="Close" class="actions-onclick"><em
                            class="fa fa-close action-icon text-danger"></em></a>

                             
                </div>
            </div>
             </div>
        <AddTeam v-if="IsAssignedUser" :ProjectId="projectId" :TaskId="ParentTaskId" :Type="IsType" :TabsArray="TabsArray"  :TaskData="taskData" :projectCurrency="projectCurrency"
            :ProjectName="ProjectName" @close="IsAssignedUser = false;" @callbackfunction="FetchTaskList"></AddTeam>
        <AddImportTask v-if="ProjectTasklistingSchema" :ProjectName="ProjectName"></AddImportTask>
        <EditTask v-if="IsEditTask" :MainProjectData="ProjectDetailData" :projectdata.sync="projectdata" :projectCurrency="projectCurrency"
            @callbackfunction="UpdateTask" :isHideSprint="isHideSprint" :NewTabName="NewTabName" :TabsArray="TabsArray" >
        </EditTask>        
        <modaltaskprogress v-if="IsUpdateProgress" :TaskItemData="TaskItemData" :Type="IsTaskType"
            @GetTaskList="GetTaskList" @CloseModal="CloseModal"> </modaltaskprogress>
    </section>
</template>
<script>
import DataService from '../../../../services/DataService.js';
import schema from '../../Project/ProjectDetailLeftAllTabs/ProjectTasklistingSchema.js';
import projectTaskAddpopup from '../../../../components/Modal/AddProjectTaskmodal.vue';
import AddImportTask from './AddImportTask.vue';
import AddTeam from '../../../../components/Modal/AddTeam.vue'
import EditTask from '../../../../components/Modal/EditTask.vue'
import modaltaskprogress from '../../../../components/Modal/modaltaskprogress.vue';
import moment from 'moment';
export default {
    components: { projectTaskAddpopup, AddTeam, AddImportTask, EditTask, modaltaskprogress },
    props: {
        projectId: {
            type: Number,
            required: true
        },
        isHideSprint: {
            type: Boolean,
            required: true
        },
        checkPmUser: {
            type: Boolean,
            required: true
        },
        NewTabName:{
            type:String,
            require: true
        },
        TabsArray:{
            type:Array
        },
        projectCurrency:{
            type:String
        }
    },
    data() {
        return {
            Key:0,
            dataTruncateLength:20,
            isTaskSave:false,
            projectdata: null,
            ProjectDetailData: null,
            IsEditTask: false,
            IsType: 'Task',
            IsTaskType: 'Project',
            TotalRecords: 0,
            noRecord: false,
            isLoading: false,
            IsPriority: null,
            CompanyId: null,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            StatusList: [],
            SortBy: '',
            SortExp: '',
            taskId: '',
            Headers: [],
            ListingData: [],
            searchCondition: '',
            Buttons: schema.buttons,
            ProjectTaskListingpopup: false,
            IsAddTask: false,
            txtTaskTitle: '',
            isSavingTask: false,
            ProjectId: 0,
            ProjectName: '',
            completionPercentage: 0,
            listActions: schema.listActions,
            IsAssignedUser: false,
            ParentTaskId: 0,
            ProjectTasklistingSchema: false,
            IsShowAction: true,
            IsUpdateProgress: false,
            TaskItemData: null,
            taskData:'',
            UserType:'',    
            projectHours: 0,
            LegendArray: [{
                class: 'text-primary fa fa-check-square mr-1',
                text: (this.$t('Task'))
            },
            {
                class: 'text-danger fa fa-warning ml-2 mr-1',
                text: (this.$t('Issue'))
            },
            {
                class: 'text-success fa fa-film text-success ml-2 mr-1',
                text: (this.$t('Story'))
            }
            ],
        }
    },
    watch: {        
        NewTabName: {
            handler(newTabName) {
                if (newTabName) {
                    this.updateHeaders(newTabName);
                }
            },
            immediate: true
        }
    },
    created: async function () {   
        var ths = this;
        ths.ProjectId = ths.projectId;
        ths.CompanyId = ths.GetUserInfo.CompanyId;
        ths.userId = ths.GetUserInfo.ID;
        ths.UserType = ths.GetUserInfo.UserType;        
        if (!ths.Headers || ths.Headers.length === 0) {
            ths.Headers = JSON.parse(JSON.stringify(schema.TableHeader));
        }
        if (ths.NewTabName) {
            ths.updateHeaders(ths.NewTabName);
        }
        ths.StatusDropdown();
        ths.GetProjectPriority();
        await ths.ProjectOverview();
        await ths.GetProjectDetails();
        await ths.FetchTaskList();
    },
    methods: {
        stripHtmlTags(text) {
        if (!text) return ''; 
        return text.replace(/<\/?[^>]+(>|$)/g, ""); 
    },
        updateHeaders(newTabName) {           
            this.Headers = JSON.parse(JSON.stringify(schema.TableHeader));
            if (newTabName && this.Headers && this.Headers.length > 0) {
                this.Headers.forEach(header => {                   
                        if (header.COLUMN_NAME === 'task_name' && header.DISPLAY_NAME === '') {
                            header.DISPLAY_NAME =`${this.$t('Key')} / ${this.$t(this.TabsArray.find(t => t.displayCode === "PROJECT_TASKS")?.displayName || 'Task')}  ${this.$t('Name')}`;
                        }
                        if (header.COLUMN_NAME === 'Team') {
                            header.DISPLAY_NAME = this.$t(this.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team');
                        }
                    
                    
                });
            }
        },
       CheckDisabled() {        
            if ((this.UserType == 'CL' || this.UserType == 'NU') && this.checkPmUser) {
                    this.Buttons[1].isvisible = true;
                    this.Buttons[2].isvisible = true;
                    this.Buttons[3].isvisible = false;
                    this.IsShowAction = true;
                    return true;
            }
            else {
                if (this.UserType == 'CA' || this.UserType == 'PM') {
                    this.Buttons[1].isvisible = true;
                    this.Buttons[2].isvisible = true;
                    this.Buttons[3].isvisible = false;
                    this.IsShowAction = true;
                    return true;
                }
                else {
                    this.Buttons[1].isvisible = false;
                    this.Buttons[2].isvisible = false;
                    this.Buttons[3].isvisible = false;
                    this.IsShowAction = false;
                    return false;                  
                }
            }
        },
        GetTaskList() {
            this.FetchTaskList();
        },
        CloseModal() {
            this.IsUpdateProgress = false;
        },
        UpdateProgress(data) {
            this.TaskItemData = data;
            this.IsUpdateProgress = true;
        },
        showAssignUser(itm) {            
            if(itm.AssignUser !=''){
                this.$set(itm, 'ispopover', true);
            }            
        },
        hideAssignUser(itm) {
            this.$set(itm, 'ispopover', false);
        },
        UpdateTask(val) {
            var vm = this;
            vm.FetchTaskList();
            if (val != undefined) {
                if (val.parent_task_id == null) {
                    vm.onExpandChild(val);
                }
            }
        },
        CompletionPercentage(itm) {
            let completionPercentage = (itm.CompleteTask / itm.TotalTask) * 100;
            if (isNaN(completionPercentage)) {
                completionPercentage = 0;
            }
            return completionPercentage.toFixed(0);
        },
        StatusDropdown: function () {
            var vm = this;
            var url = `langCode=en&companyId=${vm.CompanyId}&statusType=Project&hasGlobal=true`
            DataService.StatusListing(url).then((response) => {
                if (response.data != null && response.data != "") {
                    vm.StatusList = response.data.result.data;
                }
            });
        },
        closepopup() {
            this.ProjectTaskListingpopup = false;
        },
        async AddTask() {
            var vm=this;
            var url = 'controller=Task&action=Add'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    vm.IsAddTask = true;
                } else {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        IsHideAddTask() {
            this.IsAddTask = false;
        },
        GetProjectPriority() {
            var url = `id=&moduleName=PROJECT&type=PRIORITY&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {
                if (response.status == 200) {
                    if (response.data.DATA != undefined || response.data.DATA != null) {
                        if (response.data.DATA.length > 0) {
                            this.PriorityData = response.data.DATA;
                            var Pdata = this.PriorityData.filter(item => item.name === 'Low');
                            if (Pdata.length > 0) {
                                this.IsPriority = Pdata[0].value;
                            }
                        }
                    }
                }
            })
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Delete':
                        action.isVisible = true;
                        break;

                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchTaskList();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Deletedata":
                    this.Deletedata();
                    break;
                case "DownloadExcelData":
                    this.ExporttoExcel();
                    break;
                case "EportTask":
                    this.EportTask();
                    break;
                case "OpenAddTaskPopup":
                    this.OpenAddTaskPopup();
                    break;
                case "EditProject":                    
                    break;
                case "EditTask":
                    this.EditTask();
                    break;
                case "BackToList":
                    this.BackToList();
                    break;
            }
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'DeleteData':
                    this.DeleteTaskData(item.task_id);
                    break;

            }
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchTaskList();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        EportTask: async function () {
            var ths=this;
            var url = 'controller=Task&action=ImportTasks'
            await DataService.CheckPrivilege(url).then(async function (response) {
                
                if (response.data) {
                    
                    ths.$router.push({
                        name: "UploadExcelData", params: { projectId: ths.ProjectId, projectHours: ths.projectHours }
                    });
                } else {
                    ths.ShowAlert(ths.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },

        ExporttoExcel: async function () {
            var vueObj = this;
            vueObj.isLoading = true;
            var url = 'controller=Task&action=ExportToExcel'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    var params = `ProjectId=${vueObj.ProjectId}&TaskId=&Type=&pageSize=${1000}&pageNumber=${1}`;
                    await DataService.GetChildSprint(params).then(function (response) {
                        if (response.data.result.Data.length > 0) {
                            vueObj.TaskJSONToCSVConvertor(response.data.result, "Task", true);
                        }
                    });
                } else {
                    vueObj.isLoading = false;
                    vueObj.ShowAlert(vueObj.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },
        OpenAddTaskPopup: async function () {
            var url = 'controller=Task&action=Add'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    this.ProjectTaskListingpopup = true;
                } else {
                    this.ShowAlert(this.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },        
        BackToList: function () {
            var ths = this;
            ths.$router.push({ name: 'ProjectList' });
        },
        async SaveTask() {
            var ths = this;
            if (ths.isSavingTask || !ths.txtTaskTitle.trim()) return;

            ths.isSavingTask = true;
            ths.isLoading = true;

            const obj = {
                BackLogId: 0,
                Project_id: ths.$route.params.projectId,
                Subject: ths.txtTaskTitle,
                IssueTypeId: 'T',
                SprintId: null,
                PriorityId: ths.IsPriority,
                StatusId: 1001,
                UserId: null,
                BackLogDescription: '',
                IsBacklog: false,
                EpicId: null,
                ParentId: null,
                Type: 'TASK'
            };
            ths.txtTaskTitle = '';            
            try {
                const response = await DataService.SaveBackLog(JSON.stringify(obj));
                ths.isLoading = false;
                if (response?.data?.result?.DATA?.length > 0) {
                    ths.isTaskSave=false;
                    ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t(ths.NewTabName)]), "success", true, ths.$t("Alert"));
                    ths.FetchTaskList();
                    ths.IsShowTypeCheck = false;
                } else {
                    ths.ShowAlert(ths.$t("UnknownErrorOccur"), "failure", true, ths.$t('Alert'));
                }
            } catch (error) {
                console.error('❌ SaveTask Error:', error);
                ths.ShowAlert(ths.$t("UnknownErrorOccur"), "failure", true, ths.$t('Alert'));
            } finally {
                ths.isSavingTask = false;
            }
        },

        async ParentTask(ths) {
            var vm=this;
            var url = 'controller=Task&action=Update'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    vm.$emit('EditTask', ths);
                    vm.projectdata = ths;
                    vm.projectdata.Ispm=vm.CheckDisabled();
                    vm.MainProjectData = vm.MainProjectData;
                    vm.IsEditTask = true;
                    setTimeout(function () {
                        $("#modalEditTask").modal("show");
                    }, 1000);
                } else {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        ProjectOverview: async function () {
            var vm = this;
            var params = `projectId=${this.ProjectId}`;
            await DataService.ProjectOverview(params).then(function (response) {
                if (response.data != null > 0) {
                    vm.ProjectName = response.data.projecT_NAME;
                    vm.projectHours = response.data.estimateD_HOURS
                }
            });
        },
        getPercentage(estimatedHours,spentHours)
        {
            if (
                !estimatedHours ||
                isNaN(estimatedHours) ||
                estimatedHours <= 0 ||
                !spentHours ||
                isNaN(spentHours) ||
                spentHours <= 0
            ) {
                return 0;
            }  
              const percentage = (spentHours / estimatedHours) * 100;
            return Math.min(percentage, 100).toFixed(2);
        },
        FetchTaskList: async function () {
            var vueObj = this;
            vueObj.isLoading = true;
            var params = `ProjectId=${vueObj.ProjectId}&SprintId=&Type=&BugType=&StatusId=0&Assignee=0&sortBy=${vueObj.SortBy}&sortExp=${vueObj.SortExp}&pageSize=${vueObj.PageSize}&pageNumber=${vueObj.PageNumber}&userType=${vueObj.UserType}`;
            await DataService.GetChildSprint(params).then(function (response) {
                if (response.data.result.Data.length > 0) {
                    var updateArray = response.data.result.Data;
                    updateArray.forEach((x) => {
                      
                        if(x.status_code !='STATUS_DONE' && x.HOURSPEND !=null)
                       {
                        x.Current_Progress =vueObj.getPercentage(x.estimated_hours,x.HOURSPEND);
                       }
                        if (x.planned_start_date != null) {
                            x.planned_start_date = new Date(x.planned_start_date);
                        }
                        if (x.planned_end_date != null) {
                            x.planned_end_date = new Date(x.planned_end_date);
                        }
                        if (x.task_description != null) {
                            x.task_description = x.task_description != '' ? x.task_description.replace(/<[^>]*>/g, '') : ''
                        }
                        x.ispopover = false;
                        x.AssignUser = x.Assign != null ? x.Assign.split(',') : '';
                        x.child = {
                            onExpandChild: vueObj.onExpandChild,
                            isShowChild: false,
                            isShowExpandButton: true,
                            data: [],
                            Header: []
                        }
                    });
                    vueObj.ListingData = updateArray;
                    vueObj.TotalRecords = response.data.result.Data[0].TOTAL_RECORDS;
                    vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.PageSize);
                    vueObj.$emit('callbackWidgets');
                } else {
                    vueObj.TotalRecords = 0;
                    vueObj.TotalPages = 1;
                    vueObj.ListingData = [];
                }
            });
        },

        onExpandChild: function (item) {
            var vueObj = this;
            item.isExpanded = !item.isExpanded;
            var url = `ProjectId=${vueObj.ProjectId}&SprintId=${item.task_id}&Type=SubTask`;
            DataService.GetChildSprint(url).then((response) => {
                if (response.data.result.Data.length > 0) {
                    item.child.data = response.data.result.Data;
                    item.child.data.forEach((x) => {
                        if(x.status_code !='STATUS_DONE')
                       {
                        x.Current_Progress =vueObj.getPercentage(x.estimated_hours,x.HOURSPEND);
                       }
                        if (x.planned_start_date != null) {
                            x.planned_start_date = new Date(x.planned_start_date);
                        }
                        if (x.planned_end_date != null) {
                            x.planned_end_date = new Date(x.planned_end_date);
                        }

                        vueObj.$set(x, 'ispopover', false);
                        vueObj.$set(x, 'AssignUser', x.Assign != null ? x.Assign.split(',') : '');
                        vueObj.$set(x, 'Current_Progress', parseInt(x.Current_Progress) || 0);
                    })
                    item.child.Header = vueObj.Headers;
                    vueObj.isLoading = false;
                }
                else {
                    item.tasks = [];
                    vueObj.isLoading = false;
                }
            });
        },

        DeleteTaskData: async function (id) {
            var val = "";
            var vm=this;
            vm.isLoading = true;
            var url = 'controller=Task&action=Delete'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    if (id == null) {
                        $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                            if (val.length > 0)
                                val += ',';
                            val += $(this).val();
                        });
                    }
                    else {
                        val = id;
                    }
                    if (val != null) {
                        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Group")), function () {
                            var postJSON = {
                                ids: val,
                                moduleName: "PROJECT",
                                refCode: "TALYGEN_GLOBAL_TASK"
                            };
                            var objectPostString = JSON.stringify(postJSON);
                            DataService.CommonCommonDelete(objectPostString).then(function (response) {                                
                                vm.isLoading = false;
                                if (response.data.length>0) {
                                    if(response.data[0].Status=='Success'){
                                        if(response.data[0].Code=='TASK_ASSIGN'){
                                            vm.ShowAlert(vm.$t('Taskhavealready', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                                        }
                                        else if(response.data[0].Code=='PROGRESS'){
                                            vm.ShowAlert(vm.$t('Tasksubtaskdeleted', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                                        }
                                        else{
                                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t(vm.NewTabName)]), "success", true, vm.$t("Alert"));
                                        }
                                        vm.FetchTaskList();
                                    } 
                                    else {
                                        vm.ShowAlert(vm.$t('DeletedError', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                                    }
                                }
                                else {
                                    vm.ShowAlert(vm.$t('DeletedError', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                                }
                            });
                        });
                    }
                    else {
                        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                    }
                    vm.isLoading = false;
                } else {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        OpenAssignedUser: function (Task) {
            var vm = this;  
            vm.taskData  =   Task;  
            vm.ParentTaskId = Task.task_id;
            vm.IsAssignedUser = true;

        },

        GetProjectDetails: async function () {
            var vm = this;
            var params = `projectId=${vm.projectId}`;
            await DataService.GetProjectDetails(params).then(function (response) {
                if (response.data.result != null && response.data.result != '') {
                    vm.ProjectDetailData = (response.data.result.PROJECTOVERVIEW[0]);
                }
            });
        },

        TaskJSONToCSVConvertor: function (JSONData, fileName, ShowLabel) {
            var vm = this;            
            var arrData = typeof JSONData != 'object' ? JSON.parse(JSONData) : JSONData;
            var CSV = '<table border="1" cellpadding="10" cellspacing="10"  aria-describedby="vuecommon">><tr>';
            if (ShowLabel) {
                var row = "";
                for (var index in vm.Headers) {
                    if (vm.Headers[index].VISIBLE) {
                        var displayName = vm.Headers[index].DISPLAY_NAME;
                        var fieldName = vm.Headers[index].COLUMN_NAME;
                        if (!(displayName || /^\s*$/.test(displayName))) {
                            var chk = vm.$t(String(fieldName).toUpperCase());
                            if (chk || /^\s*$/.test(chk)) {
                                displayName = chk;
                            }
                            else {

                                chk = vm.$t(String(fieldName));
                                if (chk || /^\s*$/.test(chk)) {
                                    displayName = chk;
                                } else {
                                    displayName = fieldName;
                                }
                            }
                        }
                        else {

                            var chk = vm.$t(String(displayName).toUpperCase());
                            if (chk || /^\s*$/.test(chk)) {
                                displayName = chk;
                            } else {

                                chk = vm.$t(String(displayName));
                                if (chk || /^\s*$/.test(chk)) {
                                    displayName = chk;
                                }
                            }
                        }
                        row += ' <th scope="col">' + displayName + '</th>';
                        if (fieldName == "planned_start_date" && $("#ControllerName").val() == "project") {
                            displayName = "PlanEndDate";

                            var chk = vm.$t(String(displayName).toUpperCase());
                            if (chk || /^\s*$/.test(chk)) {
                                displayName = chk;
                            } else {

                                chk = vm.$t(String(displayName));
                                if (chk || /^\s*$/.test(chk)) {
                                    displayName = chk;
                                }
                            }
                            row += ' <th scope="col">' + displayName + '</th>';
                        }
                    }
                }
                if (fileName == "Lead-Detail") {

                    row = row + ' <th scope="col">' + vm.$t(String("LastNote")) + '</th>';
                }
                CSV += row + '</tr>';
            }
            for (var i = 0; i < arrData.Data.length; i++) {
                var row = "<tr>";
                var j = 0;
                for (var j = 0; j < vm.Headers.length; j++) {
                    if (vm.Headers[j].VISIBLE) {
                        var arrValue = ''
                        if (vm.Headers[j].COLUMN_NAME == 'planned_start_date' || vm.Headers[j].COLUMN_NAME == 'planned_end_date') {
                            arrValue = arrData.Data[i][vm.Headers[j].COLUMN_NAME] == null ? "" : moment(new Date(arrData.Data[i][vm.Headers[j].COLUMN_NAME])).format("DD/MM/YYYY");

                        } else {
                            arrValue = arrData.Data[i][vm.Headers[j].COLUMN_NAME] == null ? "" : arrData.Data[i][vm.Headers[j].COLUMN_NAME];
                        }
                        if (vm.Headers[j].COLUMN_NAME == 'Team') {
                            arrValue = arrData.Data[i].Assign != null ? arrData.Data[i].Assign : '';
                        }
                        if (vm.Headers[j].COLUMN_NAME == 'CompleteTask') {
                            arrValue = arrData.Data[i].Current_Progress;
                        }
                        row += '<td type="' + vm.Headers[j].DATA_TYPE + '">' + arrValue + '</td>';
                        if (vm.Headers[j].DATA_TYPE == 'date' && vm.Headers[j].COLUMN_NAME == "planned_start_date" && $("#ControllerName").val() == "project") {
                            arrValue = arrData.Data[i]['planned_end_date'] == null ? "" : moment(String(arrData.Data[i]['planned_end_date']), "YYYY-MM-DD").format("DD/MM/YYYY");
                            row += '<td type="' + vm.Headers[j].DATA_TYPE + '">' + arrValue + '</td>';
                        }
                    }
                }
                if (fileName == "Lead-Detail") {
                    var noteHtmlData = (arrData.Data[i]["lead_note"] == null) ? "" : arrData.Data[i]["lead_note"];
                    noteHtmlData = noteHtmlData.replace(/<div>/ig, "");
                    noteHtmlData = noteHtmlData.replace(/<\/div>/ig, '<br style="mso-data-placement:same-cell;" />');
                    var el = document.implementation.createHTMLDocument().createElement('div');
                    el.innerHTML = noteHtmlData;
                    noteHtmlData = el.innerHTML;
                    row = row + '<td type="html" data-cell-type="html" markup="html">' + noteHtmlData + '</td>';
                }
                //row= row.slice(0, row.length - 1);
                CSV += row + '</tr>';
            }
            CSV += "</table>";
            if (CSV == '') {
                growl.error("Invalid data");
                return;
            }
            var fileName = fileName;
            console.log(CSV)
            var uri = 'data:application/vnd.ms-excel;charset=utf-8,' + encodeURIComponent(CSV);
            var link = document.createElement("a");
            link.href = uri;
            link.style = "visibility:hidden";
            link.download = fileName + ".xls";
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        },
    }
}
</script>
