<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">                      
                        <h4 class="modal-title">{{ $t('Edit') }} {{ $t('Progress') }} : {{ TruncateStr(TaskItemData.task_name,25) }} </h4>      
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">                      
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="onSubmit">
                            <template v-slot:tgslot-Percentage="{ data }">
                               <div class="col-md-12 p-0 w-setpercentage">                                                   
                                    <div class="range-slider">
                                        <input id="progress-bar-1" type="range" v-model="sliderValue" max="100" class="float-left w-94 mr-2 mt-2"/>                                       
                                        <input id="slider_input" type="text" min="0" max="100"  v-on:keypress="isNumber($event)"   @input="checkMaxValue" v-model="sliderValue" class="form-control range-slider_input float-right w-4" /> 
                                    </div>
                                </div>
                            </template>
                        </dynamic-form>
                        <div class="listing border mt-3" id="divconversationbox">
                            <div class="tab-pane fade active show" v-if="CommentData.length==0">
                                <div class="row ticket-card-container card-view bg-border p-3">
                                    <div class="col-sm-12 col-md-12 col-lg-12 mt-2 text-center">
                                        <span class="text-danger "> {{ $t('NoComments') }}</span>
                                    </div>
                                </div>
                            </div>
                            <div class="col-12 d-flex border border-bottom-0 bg-f5f5f5" v-else>
                                <div class="col-md-6 pl-0">
                                    <h6 class="py-3 mb-0">
                                        {{ $t('Comments') }}
                                    </h6>
                                </div>
                                <div class="col-md-6 text-right pr-0 bottom_filter_button">
                                    <a @click="togglePanels" id="ancreplyExpandAllCollapseAll" class="position-relative" style="z-index:999;" :title="$t('ExpandAllCollapseAll')" data-toggle-tooltip="tooltip">{{ $t('ExpandAllCollapseAll') }}</a>
                                </div>
                            </div>
                            <div class="card" v-for="(item, parentIndex) in CommentData" :index="parentIndex">
                                <div class="card-header">
                                    <a class="card-link collapsed" :href="'#Expensecollapse' + parentIndex" @click.prevent="togglePanel(parentIndex)">
                                        <div class="conversation-date heading-border">
                                            <span><em class="pr-1" aria-hidden="true"></em>{{item.groupKey}}</span>
                                        </div>
                                    </a>
                                </div>
                                <div v-bind:id="'Expensecollapse'+parentIndex" v-bind:class="{'collapse':true, 'show':parentIndex==0}" :class="{'collapse': true, 'show': item.isOpen}">
                                    <div class="card-body" v-for="(childItem, childIndex) in item.groupData" :key="childIndex">
                                        <div class="conversation-main">    
                                                                                                    
                                            <div class="conversation-time"><span>{{$options.filters.formatTime(childItem.created_at)}}</span></div>
                                            <div class="conversation-box-con">
                                                <div class="conversation-box">
                                                    <div class="name-circle" style="background: rgb(195 207 213 / 84%);">
                                                        <span class="initials">
                                                            {{ getFirstTwoInitials(childItem.USER_NAME) }}
                                                        </span>
                                                    </div>
                                                    
                                                    <div class="conversation-header addednote-ticket">
                                                        <span>
                                                            <span class="sender-name">{{ childItem.USER_NAME }}</span>                                                       
                                                        </span>
                                                    </div>
                                                    <div class="conversation-content">
                                                        <div class="col-12 p-0 notesdata">
                                                            <h6 class="text-muted"><i> {{ $t('Progress') }}: {{ childItem.progress }} % </i></h6>
                                                        </div>
                                                    </div>
                                                    <div class="conversation-content">
                                                        <div class="col-12 p-0 notesdata">
                                                            <span class="sender-name">{{ childItem.comment }}</span>   
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>                                                 
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    props: {
        TaskItemData: {
            type: Object,
            required: true
        },
        Type:{
            type: String,
            required: true
        }
    },
    data(){
        return{
            isLoading:false,
            CommentData:[],
            blobUrl:'',
            TaskPercentage:'',
            AllocationModal: null,
            task_Id: null,            
            sliderValue: 0,
            TaskItem: null,
            TaskComments: '',
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [               
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextField",                                                
                            label: this.$t('Task Name'),
                            name: "TaskName",
                            value: "",  
                            disabled:true,                          
                            placeholder: this.$t('Select Tag'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",                                                
                            label: this.$t('Percentage'),
                            name: "Percentage",
                            value: "", 
                            config: {
                                options: []
                            },                           
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Comments'),
                            name: "Comments",
                            value: "",  
                            validationRules: { "required": true, max: 4000 },
                            config: {
                                rows:3
                            }
                        }
                    ]
                }                
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true,                    
                    onClick: this.OnSubmit
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }
    },  
    created:function(){
        var ths=this;
        ths.BindValue();
        ths.GetBlobUrl();
        ths.GetTaskComment(ths.TaskItemData.task_id);        
    },
    methods:{  
        togglePanels() {            
            const anyOpen = this.CommentData.some(item => item.isOpen);
            this.CommentData.forEach(item => {item.isOpen = !anyOpen; });
        },
        togglePanel(index) {
            this.CommentData[index].isOpen = !this.CommentData[index].isOpen; 
        },
        GetBlobUrl: function () {
            DataService.GetBlobUrl().then((response) => { 
                var url = response.data[0].CONFIG_DATA_VALUE;
                if(this.avatar==null){
                    this.blobUrl = '/Content/images/DefaultImages/uc_user_new.jpg';
                }
                else{
                    this.blobUrl = url + '/' + this.containerName + '/' + 'Upload' + '/' + 'UserProfileImage' + '/' + this.avatar
                } 
            })
        },  
        GetTaskComment:function(taskId){
            var ths =this;
            var url=`taskId=${taskId}`
            DataService.GetTaskComment(url).then((response)=>{                
                if(response.data.result.length>0){
                    var fullJSON=response.data.result;
                    ths.CommentData = [];
                    var gruopBy = "";
                    $.each(fullJSON,$.proxy(function(index,item){                        
                        gruopBy=ths.$options.filters.formatDate(item.created_at);
                        var chkGroup = $.grep(ths.CommentData, function (element, index) {                            
                            return element.groupKey == gruopBy;
                            }
                        );
                        if (chkGroup.length == 0) {
                            var returnedData = $.grep(fullJSON,function (element, index) {                                
                                return ths.$options.filters.formatDate(element.created_at) == gruopBy;
                              }
                         );
                        if (returnedData.length > 0) {
                            var objGroup = {
                              groupKey: gruopBy,
                              isOpen: false ,
                              groupData: returnedData,
                            };
                            ths.CommentData.push(objGroup);                           
                            ths.avatar=ths.CommentData[0].groupData[0].avatar;                            
                        }
                    }
                    },this));  
                }else{
                    ths.CommentData = [];
                }
            });
        },   
        BindValue:function(){
            var ths=this;
            ths.FormSchema[0].Data[0].value=ths.TaskItemData.task_name;
            //ths.FormSchema[0].Data[2].value=ths.TaskItemData.task_description;
            ths.sliderValue = ths.TaskItemData.Current_Progress;
        },
        isNumber(evt) {
            const charCode = evt.which ? evt.which : evt.keyCode;         
            if (charCode < 48 || charCode > 57) {
            evt.preventDefault();
            }
        },
        checkMaxValue() {
            let val = Number(this.sliderValue);
            if (val > 100) val = 100;
            if (val < 0 || isNaN(val)) val = 0;

            this.sliderValue = val; // ensures no "010"
        },
        Close:function(){
            debugger
            this.$emit('CloseModal');
        },
        getFirstTwoInitials(fullName) {
            if (!fullName) return "";

            const parts = fullName.trim().split(/\s+/);
            return (parts[0][0] + (parts[1]?.[0] || "")).toUpperCase();
        },
        onSubmit:function(){   
            var ths =this;
            var obj = {
                TaskID: ths.TaskItemData.task_id,
                Progress: ths.sliderValue,
                Comment: ths.FormSchema[0].Data[2].value,
            };
            var url =JSON.stringify(obj);
            DataService.SaveTaskLog(url).then((response)=>{                
                if(response.data.result.length>0){
                    if(response.data.result[0].LOG_ID>0){
                        ths.ShowAlert(ths.$t('CreatedSuccessfully',[ths.$t('Progress')]), "success", true,  ths.$t("Alert"));  
                        ths.Close();
                        ths.$emit('GetTaskList');   
                    }
                }
            });  

        }
    }
}
</script>

<style>
.initials.user-img-con{ line-height: 36px;text-align: center; font-size: 12px; font-weight: 400; background: rgba(195, 207, 213, 0.84);}
.name-circle .initials{ line-height: 55px; text-align: center; font-size: 16px; font-weight: 400;}

</style>